{:version=>3, :sections=>[{:offset=>{:line=>0, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/game_system/Garactier.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  module GameSystem\n    class Garactier < Base\n      # ゲームシステムの識別子\n      ID = \"Garactier\"\n\n      # ゲームシステム名\n      NAME = \"ガラクティア\"\n\n      # ゲームシステム名の読みがな\n      SORT_KEY = \"からくていあ\"\n\n      HELP_MESSAGE = <<~TEXT\n        ガラクティアVer1.04\n        x:基準値\n        y:目標値\n        x, yについては四則演算の入力が可能\n\n        ■達成値の算出(GRx)\n          クリティカル・ファンブルの判定、達成値の表示を行う。\n        ■通常判定(GRx>=y)\n          通常の判定を行う。\n        ■命中判定(GRHx>=y)\n          命中判定を行う。\n        ■回避判定(GRDx>=y)\n          回避判定を行う。\n        ■抵抗判定(GRMx>=y)\n          抵抗判定を行う。\n        ■探索成功マスレベル算出(GRSx)\n          探索・索敵判定時の最大成功マスレベル(ML)を算出する\n        ■ 表\n          アイテム決定表(ITMn)\n            ランクnのアイテム表を振る。例)ITM2 ランク２アイテム表\n            上級アイテムの判定も行います。\n          命中部位決定表(BUI)\n            命中時の部位を決定します。\n          増強可能施設決定表(SST)\n            報告フェイズの増強可能施設を決定します。\n      TEXT\n\n      #  アイテム用テーブル\n      ITEM_TABLES = {\n        'ITM2' => DiceTable::D66Table.new(\n          'ランク２アイテム決定表',\n          D66SortType::NO_SORT,\n          {\n            11 => 'リペアスプレー',\n            12 => '防壁シャボン',\n            13 => '応援ボットちゃん',\n            14 => '偵察ボットちゃん',\n            15 => '回収ボットちゃん',\n            16 => 'ブラストチャージャー',\n            21 => '仕掛け爆弾',\n            22 => 'おなじみドリル',\n            23 => '清掃ボットちゃん',\n            24 => '突撃ボットちゃん',\n            25 => '修繕ボットちゃん',\n            26 => 'アンプリファイア',\n            31 => 'コバルトエール',\n            32 => 'カステラ',\n            33 => 'エアガン',\n            34 => '安全靴',\n            35 => 'ヘルメット',\n            36 => 'フラッシュバルブ',\n            41 => 'クリアワックス',\n            42 => '目薬',\n            43 => 'ラプチャーヒール',\n            44 => '防弾盾',\n            45 => 'プレートアーマー',\n            46 => 'ホーリーチャーム',\n            51 => 'カーネルシガー',\n            52 => 'ニトロキャンディー',\n            53 => '鉱樹の花飾り',\n            54 => 'アンプルシューター',\n            55 => 'メタル包帯',\n            56 => '炸裂発煙筒',\n            61 => 'シグナルドラッグ',\n            62 => '毒手',\n            63 => 'グルーガン',\n            64 => '縫い針',\n            65 => 'パイロン',\n            66 => '☆上級品☆',\n          }\n        ),\n        'ITM3' => DiceTable::D66Table.new(\n          'ランク３アイテム決定表',\n          D66SortType::NO_SORT,\n          {\n            11 => 'バナナ',\n            12 => 'イージーバズーカ',\n            13 => 'マルチバーニア',\n            14 => '赤い鉢巻き',\n            15 => 'カクテルポイズン',\n            16 => 'リペアジェル',\n            21 => '金砕棒',\n            22 => 'オシャレステッキ',\n            23 => '掃除機',\n            24 => 'ソーラーキャップ',\n            25 => 'タクティカルベスト',\n            26 => 'ホイッスル',\n            31 => 'パノラマバイザー',\n            32 => 'フリーズランチャー',\n            33 => 'オシャレスーツ',\n            34 => '暗器',\n            35 => '無限軌道',\n            36 => 'イルミネーション',\n            41 => '光線銃',\n            42 => '十手',\n            43 => '銅鑼',\n            44 => 'オシャレハット',\n            45 => '忍び足',\n            46 => '釣り竿',\n            51 => 'ブラックパウダー',\n            52 => 'ダーティーマント',\n            53 => 'バッテリーケイン',\n            54 => 'バンデッドショルダー',\n            55 => 'オシャレシューズ',\n            56 => 'サテライト',\n            61 => 'キーパーゴーレム',\n            62 => '混迷香',\n            63 => '応援旗',\n            64 => '黒子頭巾',\n            65 => 'バーナーランス',\n            66 => '☆上級品☆',\n          }\n        ),\n        'ITM4' => DiceTable::D66Table.new(\n          'ランク４アイテム決定表',\n          D66SortType::NO_SORT,\n          {\n            11 => '金塊',\n            12 => 'パラボラアンテナ',\n            13 => 'くらましの敷布',\n            14 => '無影灯',\n            15 => '油圧ショベル',\n            16 => 'マシンテール',\n            21 => '黒曜石の像',\n            22 => '黄金のクローバー',\n            23 => '朝霧の箒',\n            24 => 'ヘッドキャノン',\n            25 => 'レッグバルカン',\n            26 => 'ダイナモブロック',\n            31 => 'ジョウロ',\n            32 => 'スナイパーライフル',\n            33 => 'おてがるスコープ',\n            34 => 'ドーザーブレード',\n            35 => 'テツゲタ',\n            36 => 'ジェットスラスター',\n            41 => '宝剣',\n            42 => '指揮棒',\n            43 => '大兜',\n            44 => '妖精さん',\n            45 => 'ロングホーン',\n            46 => '鎖がま',\n            51 => '鳥籠',\n            52 => 'カタパルトアーム',\n            53 => 'スタンドマイク',\n            54 => '臆病なカカシ',\n            55 => 'ローラーダッシュ',\n            56 => 'モミジ',\n            61 => 'マスターキー',\n            62 => '隠れ蓑',\n            63 => '番傘',\n            64 => '駆動甲冑',\n            65 => '波紋の杖',\n            66 => '☆上級品☆',\n          }\n        ),\n        'ITM5' => DiceTable::D66Table.new(\n          'ランク５アイテム決定表',\n          D66SortType::NO_SORT,\n          {\n            11 => '因果の卵',\n            12 => 'ランプ',\n            13 => '常盤の琥珀',\n            14 => '新緑の冠',\n            15 => '萌芽の靴',\n            16 => '星の骸',\n            21 => '夜の帳',\n            22 => 'スリップブローチ',\n            23 => '拳法着',\n            24 => 'めがね',\n            25 => '白旗',\n            26 => 'ディラックナイフ',\n            31 => 'エレキドレッサー',\n            32 => 'ネイルガン',\n            33 => '木漏れ日のポプリ',\n            34 => 'ミスリルピッケル',\n            35 => 'デスマッチカフス',\n            36 => 'アダムスキースカート',\n            41 => '主砲',\n            42 => 'マイクロポッド',\n            43 => '樹皮の円盤',\n            44 => 'リンゴと蛇の紋章',\n            45 => 'セントリーガンナー',\n            46 => '化生の仮面',\n            51 => 'ガトリング',\n            52 => 'オカモチ',\n            53 => '芭蕉扇',\n            54 => 'ハッピートリガー',\n            55 => '蠢く湿布',\n            56 => 'メガホン',\n            61 => 'トランシーバー',\n            62 => '好奇の鋲',\n            63 => 'スレッジハンマー',\n            64 => 'セントール',\n            65 => 'ケーブルナイト',\n            66 => '☆上級品☆',\n          }\n        ),\n        'ITM6' => DiceTable::D66Table.new(\n          'ランク６アイテム決定表',\n          D66SortType::NO_SORT,\n          {\n            11 => '禍福の勾玉',\n            12 => '祭壇',\n            13 => 'ネジまき心臓',\n            14 => 'まどろみの頭蓋',\n            15 => '猛進拍車',\n            16 => '炉心結晶',\n            21 => '狂奔の鞭',\n            22 => '暁のベル',\n            23 => 'ネコシッポ',\n            24 => '鬼蜘蛛',\n            25 => '戦上手の脚',\n            26 => '薄絹の外套',\n            31 => 'ネコクロー',\n            32 => 'クライムチャンバー',\n            33 => '古の灯火',\n            34 => 'かしこい触手',\n            35 => 'オペラグラス',\n            36 => '大鉄拳',\n            41 => '妖刀',\n            42 => 'ヘビーライター',\n            43 => '緋緋色の針',\n            44 => 'バーサクシール',\n            45 => '光芒のアンクレット',\n            46 => 'ネコブーツ',\n            51 => '旅するコイン',\n            52 => '光子鏡壁',\n            53 => 'フェザージャケット',\n            54 => 'レーザーミニオン',\n            55 => 'マニピュレーター',\n            56 => 'ランパートシールド',\n            61 => '選定者の瞳',\n            62 => '打ち上げ花火',\n            63 => '魔笛',\n            64 => '指輪',\n            65 => 'ネコミミ',\n            66 => '☆上級品☆',\n          }\n        ),\n      }.freeze()\n\n      # 施設表\n      SISETSU_TABLES = {\n        \"SST\" => DiceTable::Table.new(\n          \"増強可能施設決定表\",\n          \"1D6\",\n          [\n            '広場　マーケット　楽団',\n            '広場　ガレージ　鉄工所',\n            '広場　訓練場　農園　保健所',\n            '広場　学舎　骨董屋',\n            '広場　塗装工　菓子屋　貯蔵庫',\n            '広場　診療所　礼拝堂',\n          ]\n        ),\n      }.freeze\n\n      # 部位表\n      BUI_TABLES = {\n        \"BUI\" => DiceTable::Table.new(\n          \"命中部位決定表\",\n          \"1D6\",\n          [\n            '頭部',\n            '胴体',\n            '右腕',\n            '左腕',\n            '脚部',\n            '任意部位',\n          ]\n        ),\n      }.freeze\n\n      register_prefix('^GR[HDMS]?', 'ITM[2-6]', 'BUI', 'SST')\n\n      def eval_game_system_specific_command(command)\n        cmd_gr(command) ||\n          roll_item(command) ||\n          roll_tables(command, BUI_TABLES) ||\n          roll_tables(command, SISETSU_TABLES)\n      end\n\n      # GR系コマンドの分割\n      def cmd_gr(command)\n        case command\n        when /^GRS/\n          roll_search(command)\n        when /^GR[HDM]/\n          roll_target(command)\n        when /^GR/\n          roll_gr(command)\n        end\n      end\n\n      # 探索・索敵判定\n      def roll_search(command)\n        m = %r{^GRS([+-/*\\d]+)?$}.match(command)\n        unless m\n          return nil\n        end\n\n        modifier = Arithmetic.eval(m[1] || \"\", RoundType::FLOOR) || 0\n\n        dice_result = roll_dice_with_modifier(modifier)\n        r = determine_no_target_result(\"S\", dice_result[:total], dice_result[:critical], dice_result[:fumble])\n\n        r.text = \"(\#{m[0]}) ＞ \#{dice_result[:dice_sum]}[\#{dice_result[:dice_list].join(',')}]\#{m[1]} ＞ \#{dice_result[:total]} ＞ \#{r.text}\"\n        return r\n      end\n\n      # 目標値を持つ判定ロール\n      def roll_target(command)\n        m = %r{^GR([HDM])([+-/*\\d]+)?(?:>=?([+-/*\\d]+)+)$}.match(command)\n        unless m\n          return nil\n        end\n\n        roll_type = m[1].to_str\n        modifier = Arithmetic.eval(m[2] || \"\", RoundType::FLOOR) || 0\n        target = Arithmetic.eval(m[3] || \"\", RoundType::FLOOR) || 0\n\n        dice_result = roll_dice_with_modifier(modifier)\n        r = determine_target_result(roll_type, dice_result[:total], target, dice_result[:critical], dice_result[:fumble])\n\n        r.text = \"(\#{m[0]}) ＞ \#{dice_result[:dice_sum]}[\#{dice_result[:dice_list].join(',')}]\#{m[2]} ＞ \#{dice_result[:total]} ＞ \#{r.text}\"\n        return r\n      end\n\n      # GRのみの基本判定\n      def roll_gr(command)\n        m = %r{^GR([+-/*\\d]+)?(>=)?\\(?([+-/*\\d]+)?\\)?$}.match(command)\n        unless m\n          return nil\n        end\n\n        modifier = Arithmetic.eval(m[1] || \"\", RoundType::FLOOR) || 0\n\n        target_flag = !m[2].nil?\n        dice_result = roll_dice_with_modifier(modifier)\n\n        if target_flag\n          target = Arithmetic.eval(m[3] || \"\", RoundType::FLOOR) || 0\n          r = determine_target_result(\"\", dice_result[:total], target, dice_result[:critical], dice_result[:fumble])\n        else\n          r = determine_no_target_result(\"\", dice_result[:total], dice_result[:critical], dice_result[:fumble])\n        end\n        r.text = \"(\#{m[0]}) ＞ \#{dice_result[:dice_sum]}[\#{dice_result[:dice_list].join(',')}]\#{m[1]} ＞ \#{dice_result[:total]} ＞ \#{r.text}\"\n        return r\n      end\n\n      # 基準値(modifier)をもとに2d6+基準値の判定を行う\n      def roll_dice_with_modifier(modifier)\n        dice_list = randomizer.roll_barabara(2, 6)\n        dice_sum = dice_list.sum\n        total = dice_sum + modifier\n        critical_flag = dice_list.count(6) == 2\n        fumble_flag = dice_list.count(1) == 2\n        return {dice_list: dice_list, dice_sum: dice_sum, total: total, critical: critical_flag, fumble: fumble_flag}\n      end\n\n      # roll_typeごとにResultを作成（目標値あり）\n      def determine_target_result(roll_type, total, target, critical, fumble)\n        case roll_type\n        when \"H\"\n          if critical\n            Result.critical(\"クリティカル命中\")\n          elsif fumble\n            Result.fumble(\"ファンブル\")\n          elsif total >= target + 4\n            Result.success(\"急所命中\")\n          elsif total >= target\n            Result.success(\"命中\")\n          else\n            Result.failure(\"失敗\")\n          end\n        when \"D\"\n          if critical\n            Result.critical(\"クリティカル\")\n          elsif fumble\n            Result.fumble(\"ファンブル\")\n          elsif total >= target\n            Result.success(\"回避成功\")\n          elsif total >= target - 4\n            Result.failure(\"半減命中\")\n          else\n            Result.failure(\"失敗\")\n          end\n        when \"M\"\n          # 抵抗判定は基準値以上(激情)のほうが悪い効果のことが多いためResultを反転[6,6]の場合にファンブル\n          if critical\n            Result.fumble(\"必ず激情\")\n          elsif fumble\n            Result.critical(\"必ず平静\")\n          elsif total >= target\n            Result.failure(\"激情\")\n          else\n            Result.success(\"平静\")\n          end\n        else\n          if critical\n            Result.critical(\"クリティカル\")\n          elsif fumble\n            Result.fumble(\"ファンブル\")\n          elsif total >= target\n            Result.success(\"成功\")\n          else\n            Result.failure(\"失敗\")\n          end\n        end\n      end\n\n      # roll_typeごとにResultを作成（目標値なし）\n      def determine_no_target_result(roll_type, total, critical, fumble)\n        case roll_type\n        when \"S\"\n          if critical\n            Result.critical(\"クリティカル\")\n          elsif fumble\n            Result.fumble(\"ファンブル\")\n          else\n            success_level = ((total - 4) / 2).floor\n            if success_level >= 11\n              success_level = 11\n            elsif success_level <= 0\n              success_level = 1\n            end\n            r = Result.new\n            r.text = \"成功ML \#{success_level}\"\n            return r\n          end\n        else\n          if critical\n            Result.critical(\"クリティカル\")\n          elsif fumble\n            Result.fumble(\"ファンブル\")\n          else\n            r = Result.new\n            r.text = \"達成値 \#{total}\"\n            return r\n          end\n        end\n      end\n\n      ## アイテム表ロール ランク\n      def roll_item(command)\n        unless command.include?(\"ITM\")\n          return nil\n        end\n\n        # 1回目のアイテムロール\n        result = roll_tables(command, ITEM_TABLES)\n        # 上級判定\n        if result.include?(\"(66)\")\n          result = roll_tables(command, ITEM_TABLES) + \"*上級アイテム*\"\n        end\n        # 選択判定\n        if result.include?(\"(66)\")\n          result = \"上級アイテムを自由選択！！\"\n        end\n        return result\n      end\n    end\n  end\nend\n"], :names=>["<main>", "<module:BCDice>", "<module:GameSystem>", "<class:Garactier>", "DiceTable::D66Table", "DiceTable", "new", "D66SortType::NO_SORT", "D66SortType", "11", "12", "13", "14", "15", "16", "21", "22", "23", "24", "25", "26", "31", "32", "33", "34", "35", "36", "41", "42", "43", "44", "45", "46", "51", "52", "53", "54", "55", "56", "61", "62", "63", "64", "65", "66", "freeze", "DiceTable::Table", "self", "register_prefix", "eval_game_system_specific_command", "command", "$ret_or_1", "$ret_or_2", "$ret_or_3", "cmd_gr", "roll_item", "roll_tables", "BUI_TABLES", "SISETSU_TABLES", "roll_search", "roll_target", "roll_gr", "m", "match", "modifier", "Arithmetic", "eval", "[]", "1", "RoundType::FLOOR", "RoundType", "0", "dice_result", "roll_dice_with_modifier", "r", "determine_no_target_result", "text=", "join", "text", "roll_type", "to_str", "2", "target", "3", "determine_target_result", "target_flag", "nil?", "!", "dice_list", "randomizer", "roll_barabara", "6", "dice_sum", "sum", "total", "+", "critical_flag", "count", "==", "fumble_flag", "critical", "fumble", "Result", ">=", "4", "success", "failure", "-", "success_level", "/", "floor", "<=", "include?", "result", "ITEM_TABLES", "Base"], :mappings=>"AAAAA,2BAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;;QAEE,8BAAKA,WAAL;QAGA,gCAAOA,QAAP;QAGA,oCAAWA,QAAX;QAEA,wCACNA,iBADqB,GAErBA,SAFqB,GAGrBA,SAHqB,GAIrBA,uBAJqB,GAKrBA,IALqB,GAMrBA,gBANqB,GAOrBA,gCAPqB,GAQrBA,iBARqB,GASrBA,eATqB,GAUrBA,kBAVqB,GAWrBA,cAXqB,GAYrBA,kBAZqB,GAarBA,cAbqB,GAcrBA,kBAdqB,GAerBA,cAfqB,GAgBrBA,sBAhBqB,GAiBrBA,iCAjBqB,GAkBrBA,OAlBqB,GAmBrBA,mBAnBqB,GAoBrBA,sCApBqB,GAqBrBA,uBArBqB,GAsBrBA,kBAtBqB,GAuBrBA,qBAvBqB,GAwBrBA,oBAxBqB,GAyBrBA,4BAzBM;QA6BA,uCAAc,kDAAA,QACFC,IAAAC,eAAAD,aAAmBE,KAAAA,CAC3BH,aADQ,EAERI,IAAAC,iBAAAD,YAFQ,EAGR,MACEE,EADF,EACQN,SADR,EAEEO,EAFF,EAEQP,QAFR,EAGEQ,EAHF,EAGQR,UAHR,EAIES,EAJF,EAIQT,UAJR,EAKEU,EALF,EAKQV,UALR,EAMEW,EANF,EAMQX,YANR,EAOEY,EAPF,EAOQZ,OAPR,EAQEa,EARF,EAQQb,SARR,EASEc,EATF,EASQd,UATR,EAUEe,EAVF,EAUQf,UAVR,EAWEgB,EAXF,EAWQhB,UAXR,EAYEiB,EAZF,EAYQjB,UAZR,EAaEkB,EAbF,EAaQlB,SAbR,EAcEmB,EAdF,EAcQnB,MAdR,EAeEoB,EAfF,EAeQpB,MAfR,EAgBEqB,EAhBF,EAgBQrB,KAhBR,EAiBEsB,EAjBF,EAiBQtB,OAjBR,EAkBEuB,EAlBF,EAkBQvB,UAlBR,EAmBEwB,EAnBF,EAmBQxB,SAn